int main()
{
    const char* planets[8] = {
        "Mercury", "Venus", "Earth", "Mars",
        "Jupiter", "Saturn", "Uranus", "Neptune"
    };

    int index{};
    std::cin >> index;

    std::cout << planets[index] << '\n';

    return 0;
}

