#include <iostream>

int main()
{
    const char* colors[5] = {"red", "green", "blue", "gold", "gray"};
    char ch{};
    std::cin >> ch;

    bool found = false;
    for (int i = 0; i < 5; ++i)
    {
        if (colors[i][0] == ch)
        {
            std::cout << colors[i] << '\n';
            found = true;
        }
    }

    if (!found)
        std::cout << "Not found\n";

    return 0;
}

solution_code:
#include <iostream>

int main()
{
    const char* colors[5] = {"red", "green", "blue", "gold", "gray"};
    char ch{};
    std::cin >> ch;

    bool found = false;
    for (int i = 0; i < 5; ++i)
    {
        if (colors[i][0] == ch)
        {
            std::cout << colors[i] << '\n';
            found = true;
            break;
        }
    }

    if (!found)
        std::cout << "Not found\n";

    return 0;
}
